# Normalize for comparison (strip whitespace, lowercase)
def normalize(s):
    return ' '.join(s.split()).lower()

csv_norm = {normalize(n): n for n in csv_names}
wp_norm = {}
for wp_id, name in wp.items():
    key = normalize(name)
    if key not in wp_norm:
        wp_norm[key] = []
    wp_norm[key].append((wp_id, name))

# Find matches and mismatches
matched_ids = set()
for cn in csv_norm:
