input.command:
# Check the actual dimensions of the working marker images
/Users/dcambria/scripts/server-tools/v2/docker-dev/common/bin/docker-dev.sh wp --url="https://cambrasmax.local:8484/cultura/" eval '
// Check dimensions of the marker images
$ids = [76379, 76393, 76383]; // Arte digital, Arte urbana, Artes cênicas
foreach ($ids as $id) {
    $meta = wp_get_attachment_metadata($id);
    $file = get_attached_file($id);
    $title = get_the_title($id);
    echo "$title (ID $id): " . ($meta["width"] ?? "?") . "x" . ($meta["height"] ?? "?") . " — $file\n";
}

// Check the TEDx image
echo "\n--- TEDx marker ---\n";
// Get the attachment by URL pattern
$args = array(
    "post_type" => "attachment",
    "post_status" => "any",
    "s" => "tedxamazonia",
    "posts_per_page" => 5,
);
$q = new WP_Query($args);
foreach ($q->posts as $p) {
    $meta = wp_get_attachment_metadata($p->ID);
    echo $p->post_title . " (ID $p->ID): " . ($meta["width"] ?? "?") . "x" . ($meta["height"] ?? "?") . "\n";
    // Check if there are resized versions
    if (!empty($meta["sizes"])) {
        foreach ($meta["sizes"] as $size_name => $size_data) {
            echo "  $size_name: " . $size_data["width"] . "x" . $size_data["height"] . "\n";
        }
    }
}
' 2>/dev/null | grep -v '^\[38' | grep -v '╭\|╰\|│\|├\|Cores'

# The TEDx image might be in blog 1 (Network Media Library). Let me search more broadly
/Users/dcambria/scripts/server-tools/v2/docker-dev/common/bin/docker-dev.sh wp --url="https://cambrasmax.local:8484/" eval '
$args = array(
    "post_type" => "attachment",
    "post_status" => "any",
    "posts_per_page" => 10,
    "meta_query" => array(
        array(
            "key" => "_wp_attached_file",
            "value" => "tedx",
            "compare" => "LIKE",
        )
    )
);
$q = new WP_Query($args);
echo "Found: " . $q->found_posts . "\n";
foreach ($q->posts as $p) {
    $meta = wp_get_attachment_metadata($p->ID);
    $file = get_attached_file($p->ID);
    echo $p->post_title . " (ID $p->ID): " . ($meta["width"] ?? "?") . "x" . ($meta["height"] ?? "?") . " — $file\n";
    if (!empty($meta["sizes"])) {
        foreach ($meta["sizes"] as $size_name => $size_data) {
            echo "  $size_name: " . $size_data["width"] . "x" . $size_data["height"] . " — " . $size_data["file"] . "\n";
        }
    }
}
' 2>/dev/null | grep -v '^\[38' | grep -v '╭\|╰\|│\|├\|Cores'

