public function get_marker_data( $settings = array() ) {

	$type = ! empty( $settings['marker_type'] ) ? $settings['marker_type'] : 'image';

	$result = array( 'type' => null );

	$additional_classes = ! empty( $settings['marker_class'] ) ? $settings['marker_class'] : '';
