  // Find all map marker images and check their rendered vs natural sizes
  const markers = document.querySelectorAll('.jet-map-marker-image, img[class*="marker"]');
  const results = [];
  markers.forEach((img, i) => {
    results.push({
      index: i,
      src: img.src ? img.src.split('/').pop() : 'N/A',
      naturalWidth: img.naturalWidth,
      naturalHeight: img.naturalHeight,
      renderedWidth: img.offsetWidth,
      renderedHeight: img.offsetHeight,
      className: img.className,
      parentClass: img.parentElement ? img.parentElement.className : '',
      style: img.getAttribute('style') || ''
    });
  });

  // Also check the RichMarker containers
  const richMarkers = document.querySelectorAll('.jet-map-marker, [class*="jet-map-marker"]');
  const markerContainers = [];
  richMarkers.forEach((el, i) => {
    markerContainers.push({
      index: i,
      className: el.className,
      innerHTML: el.innerHTML.substring(0, 200),
      offsetWidth: el.offsetWidth,
      offsetHeight: el.offsetHeight,
      computedWidth: getComputedStyle(el).width,
      computedHeight: getComputedStyle(el).height
    });
  });

  return {
    markerImages: results.slice(0, 20),
    markerImageCount: results.length,
    richMarkers: markerContainers.slice(0, 5),
    richMarkerCount: markerContainers.length
  };
}

