() => {
  // Check ALL marker icons in the marker pane, not just .jet-map-marker-image
  const container = document.querySelector('.leaflet-container');
  const markerPane = container.querySelector('.leaflet-marker-pane');
  const allIcons = markerPane.querySelectorAll('.leaflet-marker-icon');

  const results = [];
  const byType = { withImage: 0, withoutImage: 0, cluster: 0, tedx: 0 };

  allIcons.forEach((icon, i) => {
    const img = icon.querySelector('.jet-map-marker-image');
    const isCluster = icon.classList.contains('marker-cluster');
    const innerHTML = icon.innerHTML.substring(0, 300);
    const hasTedx = innerHTML.toLowerCase().includes('tedx');

    if (isCluster) {
      byType.cluster++;
    } else if (img) {
      byType.withImage++;
      if (hasTedx) byType.tedx++;
    } else {
      byType.withoutImage++;
      if (hasTedx) byType.tedx++;
      // Sample some without images
      if (byType.withoutImage <= 3 || hasTedx) {
        results.push({
          index: i,
          className: icon.className.substring(0, 100),
          innerHTML: innerHTML,
          width: icon.offsetWidth,
          height: icon.offsetHeight,
          hasTedx: hasTedx
        });
      }
    }
  });

  return { byType, sampleNoImage: results, total: allIcons.length };
}

