input.function:
() => {
  const container = document.querySelector('.leaflet-container');
  const markerPane = container.querySelector('.leaflet-marker-pane');
  const allIcons = markerPane.querySelectorAll('.leaflet-marker-icon:not(.marker-cluster)');

  const byType = { withCustomImage: 0, withDefaultPin: 0, tedxImage: 0, total: 0 };
  const imgSrcs = {};

  allIcons.forEach((icon) => {
    byType.total++;
    const img = icon.querySelector('.jet-map-marker-image');
    if (img) {
      byType.withCustomImage++;
      const filename = img.src.split('/').pop();
      imgSrcs[filename] = (imgSrcs[filename] || 0) + 1;
      if (filename.toLowerCase().includes('tedx')) {
        byType.tedxImage++;
      }
    } else {
      byType.withDefaultPin++;
    }
  });

  return { byType, imageCounts: imgSrcs };
}

() => {
  const markers = document.querySelectorAll('.jet-map-marker-image');
  const tedx = [];
  markers.forEach((img) => {
    if (img.src.toLowerCase().includes('tedx')) {
      tedx.push({
        src: img.src.split('/').pop(),
        naturalWidth: img.naturalWidth,
        naturalHeight: img.naturalHeight,
        renderedWidth: img.offsetWidth,
        renderedHeight: img.offsetHeight,
        computedWidth: getComputedStyle(img).width,
        computedMaxWidth: getComputedStyle(img).maxWidth,
      });
    }
  });
  return tedx.slice(0, 3);
}

