() => {
  // Check how Leaflet stores the map instance on the container
  const container = document.querySelector('.leaflet-container');
  if (!container) return { error: 'No leaflet container' };

  const keys = Object.keys(container).filter(k => k.includes('leaflet'));

  // Check _leaflet_map or _leaflet_id
  const hasMap = !!container._leaflet_map;
  const leafletId = container._leaflet_id;

  // Try to find the map via L global
  let mapFromL = null;
  if (window.L && window.L.Map) {
    // Leaflet doesn't expose a global map registry directly
    // but JetEngine might store it
  }

  // Check JetEngine's map storage
  let jetMapData = null;
  if (window.JetEngine && window.JetEngine.mapsListings) {
    jetMapData = 'found JetEngine.mapsListings';
  }

  // Check for data attributes
  const dataAttrs = {};
  for (const attr of container.attributes) {
    if (attr.name.startsWith('data-')) {
      dataAttrs[attr.name] = attr.value.substring(0, 100);
    }
  }

  return {
    keys: keys,
    hasMap: hasMap,
    leafletId: leafletId,
    jetMapData: jetMapData,
    dataAttrs: dataAttrs,
    parentDataAttrs: Object.fromEntries(
      Array.from(container.parentElement.attributes)
        .filter(a => a.name.startsWith('data-'))
        .map(a => [a.name, a.value.substring(0, 100)])
    )
  };
}

