() => {
  // JetEngine stores maps in JetEngineMaps or similar global
  const globals = ['JetEngineMaps', 'jetEngineMaps', 'JetMapListingData', 'jetMapListing'];
  const found = {};
  for (const g of globals) {
    if (window[g]) found[g] = typeof window[g];
  }

  // Search for the map instance by iterating L internals
  if (window.L) {
    // Leaflet stores map references. We can find it by checking the container
    const container = document.querySelector('.leaflet-container');
    const leafletId = container._leaflet_id;

    // Try to disable scrollWheelZoom directly
    // Each Leaflet map calls L.Map and stores itself
    // We can use a MutationObserver trick, but simpler: 
    // use CSS to disable touch events

    // Actually, the best approach for Leaflet is to use the L.Map._leaflet_id lookup
    // Leaflet stores the map in the container via _leaflet property
    // Let's check all own props of the container
    const allProps = {};
    for (const key of Object.getOwnPropertyNames(container)) {
      if (key.startsWith('_')) {
        const val = container[key];
        allProps[key] = typeof val === 'object' ? (val && val.constructor ? val.constructor.name : 'object') : typeof val;
      }
    }

    return { found, leafletId, containerProps: allProps };
  }
  return { found, noL: true };
}

