() => {
    return new Promise(resolve => {
        const mapEl = document.querySelector('.jet-map-listing .leaflet-container');
        if (!mapEl) return resolve({ error: 'no leaflet container' });

        const map = jQuery('.jet-map-listing').data('mapInstance');
        const zoomBefore = map.getZoom();

        // Simulate wheel event on the map
        const wheelEvent = new WheelEvent('wheel', {
            deltaY: -120,
            bubbles: true,
            cancelable: true
        });
        mapEl.dispatchEvent(wheelEvent);

        setTimeout(() => {
            const zoomAfter = map.getZoom();
            resolve({
                zoomBefore: zoomBefore,
                zoomAfter: zoomAfter,
                zoomChanged: zoomBefore !== zoomAfter,
                scrollWheelZoomEnabled: map.scrollWheelZoom.enabled()
            });
        }, 500);
    });
}

