() => {
    const styles = getComputedStyle(document.documentElement);
    return {
        mainColor: styles.getPropertyValue('--main-color').trim(),
        backgroundOffwhite: styles.getPropertyValue('--background-offwhite').trim(),
        backgroundInvertido: styles.getPropertyValue('--background-invertido').trim(),
        scrollbarCSS: (() => {
            for (const sheet of document.styleSheets) {
                try {
                    for (const rule of sheet.cssRules) {
                        if (rule.selectorText && rule.selectorText.includes('::-webkit-scrollbar-thumb') && !rule.selectorText.includes('hover')) {
                            return { selector: rule.selectorText, background: rule.style.background };
                        }
                    }
                } catch(e) {}
            }
            return 'not found';
        })()
    };
}

