/*
 * base.css — Estilos globais e componentes base do tema
 * Extraído de: style.css
 * Tema: hello-elementor-child
 */

/* ==========================================================================
   2. ESTILOS GLOBAIS
   ========================================================================== */

/* --- 2.1 HTML & Body --- */
html {
    font-size         : 16px;
    scrollbar-gutter  : stable;
    scroll-behavior   : smooth;
}

@media (prefers-reduced-motion: no-preference) {
    :has(:target) {
        scroll-behavior   : smooth;
        scroll-padding-top: 3rem;
    }
}

html body.elementor-default {
    background-color: var(--ucpa-color-offwhite);
    overflow-x      : hidden;
    position        : relative;
}

@media (max-width: 768px) {
    html, body {
        overflow-x: hidden;
    }
}

html body.elementor-kit-2553.elementor-page-26826 {
    background-color: var(--ucpa-color-offwhite);
}

/* --- 2.2 Tipografia --- */
h1, h2, h3, h4, h5, h6 {
    text-wrap: balance;
}

#content .tituloPagina {
    margin-top: 5rem;
}

figcaption {
    text-align: center;
    color     : var(--e-global-color-text);
}

/* --- 2.3 Links --- */
html body a[href*="mailto"]:hover {
    color: currentColor;
}

.elementor-kit-2553 a:hover {
    color: var(--e-global-color-text);
}

/* Widget Bureau SVG: preserva cor no hover para não afetar fill:currentColor */
.elementor-widget-bureau_svg a:hover {
    color: inherit !important;
}

/* --- 2.4 Seleção de Texto --- */
::selection {
    background-color: var(--ucpa-color-white);
    color           : var(--ucpa-color-accent);
}

@supports (color: color-mix(in oklch, black 50%, white)) {
    ::selection {
        background-color: color-mix(in oklch, var(--ucpa-color-main) 90%, black 10%);
        color           : color-mix(in oklch, var(--ucpa-color-main) 10%, white 90%);
    }
}

/* --- 2.5 Outline --- */
* {
    outline-color: var(--e-global-color-accent);
}

/* --- 2.6 Scrollbar --- */
::-webkit-scrollbar {
    width : 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: var(--background-offwhite);  /* #DEDDD1 — offwhite do layout */
}

::-webkit-scrollbar-thumb {
    background   : var(--main-color);        /* #900042 — vinho principal */
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: var(--background-invertido); /* #C02975 — magenta hover */
}


/* ==========================================================================
   3. COMPONENTES
   ========================================================================== */

/* --- 3.1 Labels --- */
html body.elementor-kit-2553 label {
    color: var(--ucpa-color-main, #000);
}

input.function:
() => {
    // Verificar as regras de scrollbar com fallback
    const results = [];
    for (const sheet of document.styleSheets) {
        try {
            if (!sheet.href || !sheet.href.includes('hello-elementor-child/css/base.css')) continue;
            for (const rule of sheet.cssRules) {
                if (rule.selectorText && rule.selectorText.includes('::-webkit-scrollbar')) {
                    results.push({
                        selector: rule.selectorText,
                        cssText: rule.cssText
                    });
                }
            }
        } catch(e) {}
    }

    // Verificar a cor resolvida do thumb
    const test = document.createElement('div');
    document.body.appendChild(test);
    test.style.color = 'var(--main-color, #900042)';
    const thumbColor = getComputedStyle(test).color;
    test.style.color = 'var(--background-offwhite, #DEDDD1)';
    const trackColor = getComputedStyle(test).color;
    test.style.color = 'var(--background-invertido, #C02975)';
    const hoverColor = getComputedStyle(test).color;
    document.body.removeChild(test);

    return { rules: results, resolved: { thumbColor, trackColor, hoverColor } };
}

