    const cs = getComputedStyle(document.documentElement);
    return {
        baseHref,
        htmlRule,
        scrollbarColor: cs.scrollbarColor || cs.getPropertyValue('scrollbar-color'),
        scrollbarWidth: cs.scrollbarWidth || cs.getPropertyValue('scrollbar-width')
    };
}

