() => {
    const root = document.documentElement;
    const cs = getComputedStyle(root);

    // Pegar todas as --e-global-color-* que estão definidas
    const colors = {};
    const allSheets = [...document.styleSheets];

    for (const sheet of allSheets) {
        try {
            for (const rule of sheet.cssRules) {
                if (rule.selectorText === ':root' || rule.selectorText === 'body') {
                    const text = rule.cssText;
                    const matches = text.matchAll(/--e-global-color-([a-z0-9]+)\s*:\s*([^;]+)/g);
                    for (const m of matches) {
                        colors['--e-global-color-' + m[1]] = m[2].trim();
                    }
                }
            }
        } catch(e) {}
    }

    return { count: Object.keys(colors).length, colors };
}

